ment Tourism Office 2025 DTW Data', 'https://disparda.baliprov.go.id/data-daya-tarik-wisata-dan-desa-wisata-tahun-2025-provinsi-bali/2025/03/', -8.5922, 115.3342, 4.6, 37000) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_id = EXCLUDED.name_id, island = EXCLUDED.island, province = EXCLUDED.province, city = EXCLUDED.city, category_key = EXCLUDED.category_key, category_id = EXCLUDED.category_id, category_en = EXCLUDED.category_en, short_description_id = EXCLUDED.short_description_id, short_description_en = EXCLUDED.short_description_en, description_id = EXCLUDED.description_id, description_en = EXCLUDED.description_en, image_url = EXCLUDED.image_url, address = EXCLUDED.address, google_maps_url = EXCLUDED.google_maps_url, activities_id = EXCLUDED.activities_id, activities_en = EXCLUDED.activities_en, best_time_to_visit_id = EXCLUDED.best_time_to_visit_id, best_time_to_visit_en = EXCLUDED.best_time_to_visit_en, travel_notes_id = EXCLUDED.travel_notes_id, travel_notes_en = EXCLUDED.travel_notes_en, source_name = EXCLUDED.source_name, source_url = EXCLUDED.source_url, latitude = EXCLUDED.latitude, longitude = EXCLUDED.longitude, seed_rating = EXCLUDED.seed_rating, seed_review_count = EXCLUDED.seed_review_count;
